def parse_http_headers(headers_string):
    parsed_headers = {}
    lines = headers_string.strip().split('\n')
    for line in lines:
        line = line.strip()
        if not line:
            continue

        parts = line.split(':', 1)
        if len(parts) == 2:
            name = parts[0].strip()
            value = parts[1].strip()
            parsed_headers[name] = value

    return parsed_headers
